import{c as a,Q as s,j as t,m as i}from"./chunks/framework.BY2giUYo.js";const u=JSON.parse('{"title":"Troubleshoot the local setup","description":"","frontmatter":{"title":"Troubleshoot the local setup","personas":["platform-owner","service-provider","service-consumer"]},"headers":[],"relativePath":"how-to-guides/troubleshoot-local-setup.md","filePath":"how-to-guides/troubleshoot-local-setup.md"}'),l={name:"how-to-guides/troubleshoot-local-setup.md"};function n(o,e,r,h,p,c){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="troubleshoot-the-local-setup" tabindex="-1">Troubleshoot the local setup <a class="header-anchor" href="#troubleshoot-the-local-setup" aria-label="Permalink to &quot;Troubleshoot the local setup&quot;">​</a></h1><p>For local-setup specific issues, also check the <a href="https://github.com/platform-mesh/helm-charts/issues?q=state%3Aopen%20label%3Alocal-setup" target="_blank" rel="noreferrer">local-setup issues in the helm-charts repository</a>.</p><h2 id="docker-or-podman-is-not-running" tabindex="-1">Docker or Podman is not running <a class="header-anchor" href="#docker-or-podman-is-not-running" aria-label="Permalink to &quot;Docker or Podman is not running&quot;">​</a></h2><p>Start Docker Desktop or Podman before running the setup.</p><p>For WSL2, verify Docker Desktop WSL integration is enabled.</p><h2 id="ports-are-already-in-use" tabindex="-1">Ports are already in use <a class="header-anchor" href="#ports-are-already-in-use" aria-label="Permalink to &quot;Ports are already in use&quot;">​</a></h2><p>The local setup expects ports <code>8443</code>, <code>80</code>, and <code>443</code> to be available. Stop conflicting services before running setup.</p><h2 id="kind-cluster-creation-fails" tabindex="-1">Kind cluster creation fails <a class="header-anchor" href="#kind-cluster-creation-fails" aria-label="Permalink to &quot;Kind cluster creation fails&quot;">​</a></h2><p>Delete the existing Kind cluster and retry:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kind</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cluster</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> platform-mesh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">task</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local-setup</span></span></code></pre></div><p>Check available disk space. The setup needs about 10 GB. Also verify that the container runtime has enough CPU and memory.</p><h2 id="browser-certificate-warnings" tabindex="-1">Browser certificate warnings <a class="header-anchor" href="#browser-certificate-warnings" aria-label="Permalink to &quot;Browser certificate warnings&quot;">​</a></h2><p>Reinstall local certificates:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkcert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -install</span></span></code></pre></div><p>If warnings continue, see the <a href="https://github.com/platform-mesh/helm-charts/blob/main/local-setup/README.md#certificate-issues" target="_blank" rel="noreferrer">certificate troubleshooting guide</a>.</p><h2 id="component-timeouts" tabindex="-1">Component timeouts <a class="header-anchor" href="#component-timeouts" aria-label="Permalink to &quot;Component timeouts&quot;">​</a></h2><p>Verify that all required images can be pulled from your network. To reduce image pulling on subsequent runs, see <a href="./speed-up-local-rebuilds.html">Speed up local rebuilds</a>.</p><h2 id="enable-debug-output" tabindex="-1">Enable debug output <a class="header-anchor" href="#enable-debug-output" aria-label="Permalink to &quot;Enable debug output&quot;">​</a></h2><p>Prepend <code>DEBUG=true</code> to any setup task:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DEBUG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> task</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local-setup:iterate</span></span></code></pre></div><h2 id="wsl2-cgroup-issues" tabindex="-1">WSL2 cgroup issues <a class="header-anchor" href="#wsl2-cgroup-issues" aria-label="Permalink to &quot;WSL2 cgroup issues&quot;">​</a></h2><p>If Kubernetes crashes because of a cgroup v1 and v2 hybrid state, force WSL2 to use cgroup v2.</p><p>Open PowerShell, edit <code>%USERPROFILE%\\.wslconfig</code>, and add:</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[wsl2]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">kernelCommandLine</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">cgroup_no_v1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=all</span></span></code></pre></div><p>Restart WSL2 after saving the file.</p><h2 id="clean-up-the-local-setup" tabindex="-1">Clean up the local setup <a class="header-anchor" href="#clean-up-the-local-setup" aria-label="Permalink to &quot;Clean up the local setup&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kind</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cluster</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> platform-mesh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkcert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -uninstall</span></span></code></pre></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./set-up-platform-mesh-locally.html">Set up Platform Mesh locally</a></li><li><a href="./speed-up-local-rebuilds.html">Speed up local rebuilds</a></li><li><a href="./access-kcp-admin.html">Access the kcp admin workspace</a></li><li><a href="/pr-preview/pr-215/concepts/architecture.html">Architecture</a></li></ul>`,29)])])}const k=a(l,[["render",n]]);export{u as __pageData,k as default};
